INSERT INTO news (id, company_id, source_id, title, summary, category, source_url, sentiment, relevance_score, published_at, extracted_at, created_at) VALUES
('b1000001-0001-4000-8000-000000000001', 'a1b2c3d4-0001-4000-8000-000000000001', '00238d74-63da-4b37-88cb-ff4357db7e13', 'SNCF dévoile le TGV du futur M avec un design double-étage repensé', 'SNCF Voyageurs a présenté le TGV M (TGV du futur), coédéveloppé avec Alstom, promettant 20% de consommation en moins, 740 places et accessibilité renforcée. Livraisons prévues dès 2025 pour les lignes Sud-Est.', 'product_launch', 'https://www.sncf.com/fr/groupe/newsroom/tgv-du-futur-presentation', 'positive', 8, 1776300000, 1776520000, 1776520000);
INSERT INTO news (id, company_id, source_id, title, summary, category, source_url, sentiment, relevance_score, published_at, extracted_at, created_at) VALUES
('b1000001-0002-4000-8000-000000000002', 'a1b2c3d4-0001-4000-8000-000000000001', '00238d74-63da-4b37-88cb-ff4357db7e13', 'SNCF Réseau accélère le déploiement ERTMS sur le réseau ferré national', 'Le programme de signalisation digitale ERTMS/ETCS Niveau 2 avance sur l''axe Paris–Lyon. SNCF Réseau investit 1,2 Md€ pour la commande centralisée du réseau, réduisant les coûts de maintenance de 30%.', 'digital_transformation', 'https://www.sncf-reseau.com/fr/digital-signaling-ertms-2025', 'positive', 7, 1776000000, 1776520000, 1776520000);
INSERT INTO news (id, company_id, source_id, title, summary, category, source_url, sentiment, relevance_score, published_at, extracted_at, created_at) VALUES
('b1000001-0003-4000-8000-000000000003', 'a1b2c3d4-0001-4000-8000-000000000001', '00238d74-63da-4b37-88cb-ff4357db7e13', 'SNCF lance un programme de trains autonomes avec des essais en Nouvelle-Aquitaine', 'SNCF teste des prototypes de trains autonomes (GOA 3/4) sur la ligne Agen–Périgueux. Le projet, piloté par SNCF Tech, vise la circulation semi-autonome de TER d''ici 2028 pour pallier la pénurie de conducteurs.', 'innovation', 'https://www.sncf.com/fr/innovation/trains-autonomes-essais-2025', 'positive', 7, 1775700000, 1776520000, 1776520000);
INSERT INTO news (id, company_id, source_id, title, summary, category, source_url, sentiment, relevance_score, published_at, extracted_at, created_at) VALUES
('b1000001-0004-4000-8000-000000000004', 'a1b2c3d4-0001-4000-8000-000000000001', '00238d74-63da-4b37-88cb-ff4357db7e13', 'SNCF investit dans la data et l''IA pour la maintenance prédictive du réseau', 'SNCF Réseau déploie des capteurs IoT et des modèles de machine learning pour la maintenance prédictive des aiguillages et caténaires. Budget : 450 M€ sur 3 ans avec recours à des ESN partenaires.', 'technology', 'https://www.sncf.com/fr/innovation/maintenance-predictive-ia', 'positive', 6, 1775400000, 1776520000, 1776520000);
INSERT INTO news (id, company_id, source_id, title, summary, category, source_url, sentiment, relevance_score, published_at, extracted_at, created_at) VALUES
('b1000001-0005-4000-8000-000000000005', 'a1b2c3d4-0001-4000-8000-000000000001', '00238d74-63da-4b37-88cb-ff4357db7e13', 'SNCF contribue au Grand Paris Express via la gare de Saint-Denis Pleyel', 'SNCF Gares & Connexions participe à la construction du hub multimodal de Saint-Denis Pleyel, point de convergence des lignes 14/15/16/17 du Grand Paris Express et du RER D. Ouverture partielle JO 2024 confirmée.', 'infrastructure', 'https://www.gares-sncf.com/fr/grand-paris-express-saint-denis-pleyel', 'positive', 6, 1775100000, 1776520000, 1776520000);
INSERT INTO news (id, company_id, source_id, title, summary, category, source_url, sentiment, relevance_score, published_at, extracted_at, created_at) VALUES
('b2000001-0001-4000-8000-000000000001', 'a1b2c3d4-0002-4000-8000-000000000002', '00238d74-63da-4b37-88cb-ff4357db7e13', 'RATP pilote le Grand Paris Express : la ligne 15 Sud en essais dynamiques', 'La Société du Grand Paris a confié l''exploitation de la ligne 15 Sud à RATP. Les rames Alstom Metropolis circulent en essais sur le tronçon Pont-de-Sèvres – Noisy-Champs, avec une automatisation intégrale CBTC Urbalis 400.', 'infrastructure', 'https://www.ratp.fr/groupe/projets/grand-paris-express-ligne-15', 'positive', 8, 1776300000, 1776520000, 1776520000);
